questionvariables.text:
/* V1: E-core, Aiding Dots, Resistive Load */
L1_val: 0.05;
L2_val: 0.02;
k_val: 0.6;
i1_val: 3;
i2_val: 2;

/* Mutual inductance */
M_val: k_val*sqrt(L1_val*L2_val);

/* Stored energy: W = 1/2*L1*i1^2 + 1/2*L2*i2^2 + M*i1*i2 */
W_val: 1/2*L1_val*i1_val^2 + 1/2*L2_val*i2_val^2 + M_val*i1_val*i2_val;

/* Error values */
W_wrong_sign: 1/2*L1_val*i1_val^2 + 1/2*L2_val*i2_val^2 - M_val*i1_val*i2_val;
W_forgot_M: 1/2*L1_val*i1_val^2 + 1/2*L2_val*i2_val^2;

/* T-equivalent elements */
La_val: L1_val - M_val;
Lb_val: L2_val - M_val;

/* Turns ratio estimate */
a_val: sqrt(L1_val/L2_val);

/* Numerical versions */
M_num: float(M_val);
W_num: float(W_val);

/* Part (a) dot config MCQ */
dot_opts: random_permutation([[1, true, "Dots on top terminals of both coils (same-sense winding)"], [2, false, "Dot on top of Coil 1, dot on bottom of Coil 2"], [3, false, "Dots on bottom terminals of both coils"], [4, false, "Dot on bottom of Coil 1, dot on top of Coil 2"]]);

/* Part (d) MCQ-MA */
mcq_opts: random_permutation([[1, true, "Increase the coupling coefficient k"], [2, false, "Reverse the direction of i_2"], [3, true, "Increase L_1"], [4, false, "Decrease both i_1 and i_2 by half"], [5, false, "Replace aiding dots with opposing dots"]]);
correct_mcq: {1,3};

/* Teacher answers */
ta_dot: dot_opts;
ta_M: float(M_val);
ta_W: float(W_val);
ta_mcq: correct_mcq;

/* V2: Toroid, Opposing Dots, RL Load */
L1_val: 0.04;
L2_val: 0.01;
k_val: 0.5;
i1_val: 4;
i2_val: 3;

/* Mutual inductance */
M_val: k_val*sqrt(L1_val*L2_val);

/* Stored energy: W = 1/2*L1*i1^2 + 1/2*L2*i2^2 - M*i1*i2 */
W_val: 1/2*L1_val*i1_val^2 + 1/2*L2_val*i2_val^2 - M_val*i1_val*i2_val;

/* Error values */
W_wrong_sign: 1/2*L1_val*i1_val^2 + 1/2*L2_val*i2_val^2 + M_val*i1_val*i2_val;
W_forgot_M: 1/2*L1_val*i1_val^2 + 1/2*L2_val*i2_val^2;

/* T-equivalent elements */
La_val: L1_val + M_val;
Lb_val: L2_val + M_val;

/* Turns ratio estimate */
a_val: sqrt(L1_val/L2_val);

/* Numerical versions */
M_num: float(M_val);
W_num: float(W_val);

/* Part (a) dot config MCQ */
dot_opts: random_permutation([[1, false, "Dots on top terminals of both coils"], [2, true, "Dot on top of Coil 1, dot on bottom of Coil 2 (opposite sense)"], [3, false, "Dots on bottom terminals of both coils"], [4, false, "Dot on bottom of Coil 1, dot on top of Coil 2"]]);

/* Part (d) MCQ-MA */
mcq_opts: random_permutation([[1, false, "Increase the coupling coefficient k"], [2, true, "Increase i_1"], [3, false, "Decrease L_2"], [4, true, "Increase L_1"], [5, true, "Reverse the direction of i_2 (makes both enter dotted terminals)"]]);
correct_mcq: {2,4,5};

/* Teacher answers */
ta_dot: dot_opts;
ta_M: float(M_val);
ta_W: float(W_val);
ta_mcq: correct_mcq;

/* V3: C-core, Aiding Dots, Symmetric */
L1_val: 0.03;
L2_val: 0.03;
k_val: 0.7;
i1_val: 2;
i2_val: 2;

/* Mutual inductance */
M_val: k_val*sqrt(L1_val*L2_val);

/* Stored energy: W = 1/2*L1*i1^2 + 1/2*L2*i2^2 + M*i1*i2 */
W_val: 1/2*L1_val*i1_val^2 + 1/2*L2_val*i2_val^2 + M_val*i1_val*i2_val;

/* Error values */
W_wrong_sign: 1/2*L1_val*i1_val^2 + 1/2*L2_val*i2_val^2 - M_val*i1_val*i2_val;
W_forgot_M: 1/2*L1_val*i1_val^2 + 1/2*L2_val*i2_val^2;

/* T-equivalent elements */
La_val: L1_val - M_val;
Lb_val: L2_val - M_val;

/* Turns ratio estimate */
a_val: sqrt(L1_val/L2_val);

/* Numerical versions */
M_num: float(M_val);
W_num: float(W_val);

/* Part (a) dot config MCQ */
dot_opts: random_permutation([[1, true, "Dots on left terminals of both coils (same winding direction)"], [2, false, "Dot on left of Coil 1, dot on right of Coil 2"], [3, false, "Dots on right terminals of both coils"], [4, false, "No dots needed since L_1 = L_2"]]);

/* Part (d) MCQ-MA */
mcq_opts: random_permutation([[1, true, "Increase k toward 1.0 (tighter coupling)"], [2, true, "Increase both i_1 and i_2 equally"], [3, false, "Reduce L_1 while keeping L_2 the same"], [4, false, "Switch from aiding to opposing dot convention"], [5, false, "Decrease the frequency of the source"]]);
correct_mcq: {1,2};

/* Teacher answers */
ta_dot: dot_opts;
ta_M: float(M_val);
ta_W: float(W_val);
ta_mcq: correct_mcq;

/* V4: Rectangular Core, Opposing Dots, Tight Coupling */
L1_val: 0.06;
L2_val: 0.015;
k_val: 0.45;
i1_val: 2;
i2_val: 5;

/* Mutual inductance */
M_val: k_val*sqrt(L1_val*L2_val);

/* Stored energy: W = 1/2*L1*i1^2 + 1/2*L2*i2^2 - M*i1*i2 */
W_val: 1/2*L1_val*i1_val^2 + 1/2*L2_val*i2_val^2 - M_val*i1_val*i2_val;

/* Error values */
W_wrong_sign: 1/2*L1_val*i1_val^2 + 1/2*L2_val*i2_val^2 + M_val*i1_val*i2_val;
W_forgot_M: 1/2*L1_val*i1_val^2 + 1/2*L2_val*i2_val^2;

/* T-equivalent elements */
La_val: L1_val + M_val;
Lb_val: L2_val + M_val;

/* Turns ratio estimate */
a_val: sqrt(L1_val/L2_val);

/* Numerical versions */
M_num: float(M_val);
W_num: float(W_val);

/* Part (a) dot config MCQ */
dot_opts: random_permutation([[1, false, "Dots on the same side of both coils"], [2, true, "Dot on top of Coil 1, dot on bottom of Coil 2 (opposite winding)"], [3, false, "No dots are needed for this configuration"], [4, false, "Dots on opposite sides, but reversed from option B"]]);

/* Part (d) MCQ-MA */
mcq_opts: random_permutation([[1, false, "Increase the coupling coefficient k"], [2, true, "Increase i_2"], [3, true, "Increase L_2"], [4, false, "Decrease i_1 by half"], [5, true, "Replace opposing dots with aiding dots"]]);
correct_mcq: {2,3,5};

/* Teacher answers */
ta_dot: dot_opts;
ta_M: float(M_val);
ta_W: float(W_val);
ta_mcq: correct_mcq;
